JS_CODE = 'var parts = [\n  { name:"腕（全体）", key:"arm", medical:40000, esthetic:25000 },\n  { name:"脚（全体）", key:"leg", medical:60000, esthetic:38000 },\n  { name:"ワキ", key:"armpit", medical:30000, esthetic:18000 },\n  { name:"VIO", key:"vio", medical:80000, esthetic:50000 },\n  { name:"顔", key:"face", medical:50000, esthetic:35000 },\n  { name:"背中", key:"back", medical:55000, esthetic:35000 },\n  { name:"お腹", key:"belly", medical:45000, esthetic:28000 },\n  { name:"全身", key:"whole", medical:250000, esthetic:160000 }\n];\n\nvar selectedParts = {};\nvar selectedType = \'medical\';\n\nfunction init() {\n  var c = document.getElementById(\'parts-container\');\n  parts.forEach(function(p) {\n    var btn = document.createElement(\'button\');\n    btn.className = \'part-btn\';\n    btn.textContent = p.name;\n    btn.dataset.key = p.key;\n    btn.onclick = function() { togglePart(btn, p.key); };\n    c.appendChild(btn);\n  });\n}\n\nfunction togglePart(btn, key) {\n  if(selectedParts[key]) {\n    delete selectedParts[key];\n    btn.classList.remove(\'selected\');\n  } else {\n    if(key===\'whole\') {\n      selectedParts = {};\n      document.querySelectorAll(\'.part-btn\').forEach(function(b){ b.classList.remove(\'selected\'); });\n    } else {\n      delete selectedParts[\'whole\'];\n      document.querySelectorAll(\'.part-btn[data-key="whole"]\').forEach(function(b){ b.classList.remove(\'selected\'); });\n    }\n    selectedParts[key] = true;\n    btn.classList.add(\'selected\');\n  }\n}\n\nfunction selectType(btn, type) {\n  selectedType = type;\n  document.querySelectorAll(\'.type-btn\').forEach(function(b){ b.classList.remove(\'selected\'); });\n  btn.classList.add(\'selected\');\n}\n\nfunction calculate() {\n  if(Object.keys(selectedParts).length === 0) {\n    alert(\'部位を1つ以上選択してください\');\n    return;\n  }\n  var total = 0;\n  var breakdown = [];\n  parts.forEach(function(p) {\n    if(selectedParts[p.key]) {\n      var cost = selectedType===\'medical\' ? p.medical : p.esthetic;\n      total += cost;\n      breakdown.push({ name: p.name, cost: cost });\n    }\n  });\n\n  var sessions = selectedType===\'medical\' ? \'5〜8回\' : \'12〜18回\';\n  var period = selectedType===\'medical\' ? \'約1〜2年\' : \'約2〜3年\';\n  var monthly = Math.round(total / (selectedType===\'medical\' ? 24 : 36) / 1000) * 1000;\n\n  document.getElementById(\'r-total\').textContent = Math.round(total/10000) + \'万円\';\n  document.getElementById(\'r-sessions\').textContent = period+\'・月払いなら月\'+Math.round(monthly/1000)+\'千円〜\';\n  document.getElementById(\'r-monthly\').textContent = \'月\'+Math.round(monthly/1000)+\'千円〜\';\n  document.getElementById(\'r-count\').textContent = sessions;\n\n  var bd = document.getElementById(\'parts-breakdown\');\n  bd.innerHTML = \'<div class="space-y-2">\';\n  breakdown.forEach(function(b) {\n    bd.innerHTML += \'<div class="flex justify-between text-sm"><span class="text-gray-600">\'+b.name+\'</span><span class="font-bold">¥\'+b.cost.toLocaleString()+\'</span></div>\';\n  });\n  bd.innerHTML += \'</div>\';\n\n  var aff = document.getElementById(\'aff-area\');\n  if(selectedType===\'medical\') {\n    aff.innerHTML = \'<div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mb-2"><div class="font-bold text-rose-800 mb-1">医療脱毛クリニックの無料カウンセリング</div><p class="text-xs text-gray-600 mb-3">湘南美容・アリシア等の人気クリニックを比較。初回カウンセリング無料で正確な費用を確認。</p><a href="https://px.a8.net/svt/ejp?a8mat=4B3WJ7+18PTPM+1O96+6PRPD" rel="nofollow" target="_blank" rel="noopener sponsored" class="block text-center bg-rose-500 text-white font-bold py-3 rounded-lg text-sm hover:bg-rose-600 transition">無料カウンセリングを予約 →</a></div>\';\n  } else {\n    aff.innerHTML = \'<div class="bg-rose-50 border border-rose-200 rounded-xl p-4 mb-2"><div class="font-bold text-rose-800 mb-1">光脱毛サロンの無料体験</div><p class="text-xs text-gray-600 mb-3">ミュゼ・ストラッシュ等の人気サロン。まずは無料体験から試してみよう。</p><a href="https://px.a8.net/svt/ejp?a8mat=4B3WJ7+18PTPM+1O96+5YRHE" rel="nofollow" target="_blank" rel="noopener sponsored" class="block text-center bg-rose-500 text-white font-bold py-3 rounded-lg text-sm hover:bg-rose-600 transition">無料体験を予約する →</a></div>\';\n  }\n\n  document.getElementById(\'res'
